public int checkRecord(int n) {
    int M = 1000000007;
    long[] dp = new long[6];  // {latent state 0, latent state 1, ..., latent state 5}
    Arrays.fill(dp, 1);
    while (n-- > 0) {
        long[] next_dp = new long[6];
        next_dp[0] = (dp[0] + dp[1] + dp[2]) % M;
        next_dp[1] = dp[0];
        next_dp[2] = dp[1];
        next_dp[3] = (dp[3] + dp[4] + dp[5]) % M;
        next_dp[4] = dp[3];
        next_dp[5] = dp[4];
        dp = next_dp;
    }
    return (int) ((dp[0] + dp[1] + dp[2] +
                   dp[3] + dp[4] + dp[5]) % M);
}
```


